var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최악의 상황을 생각해서 최정예 구조팀을 꾸리고 있었는데…","JPN":"最悪の状況を想定して最精鋭の救助チームを作ってたけど……","ENG":"I was assembling an elite rescue team in anticipation of the worst-case scenario...","TWN":"考慮到最壞的情況，我正在組織最精銳的救援隊……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나한테 연락한 걸 보면 무사히 도착한 모양이네.","JPN":"私に連絡できたんだから、無事到着したようだね。","ENG":"But seeing how you called me, I guess you arrived safely.","TWN":"不過看到你聯絡我，就表示是平安到達了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다행이군. 연구에 몰두하느라 연락을 못 받으면 어쩌나 했는데 말이지.","JPN":"研究に夢中で連絡が取れなかったらどうしようかと思っていたが、そうでなくてよかった。","ENG":"That's a relief. I was worried you might not pick up being too focused on working.","TWN":"太好了。我還擔心你太專注於研究而收不到呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 난 일곱 가지 일을 동시에 할 수 있는 천재라고.","JPN":"フン、私は7つの仕事を同時にこなせる天才なんだよ。","ENG":"Hmph! I'm a genius who can multitask seven things at once.","TWN":"呃，我可是能同時做七件事的天才。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 연락을 받으면서도 내 작업은 진전을 이루는 중이니 걱정 마.","JPN":"こうやって連絡してる間にも私の作業は進展中だから心配しないで。","ENG":"I'm making progress with my work even while talking to you like this, so don't worry.","TWN":"即使在與你們通訊的同時，我的工作也在取得進展，所以不用擔心。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"일곱 가지 일을 동시에…?","JPN":"7つの仕事を同時に……？","ENG":"Seven things simultaneously...?","TWN":"同時做七件事……？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님은 동시사고 능력을 가진 카운터입니다.","JPN":"シニア様は同時思考能力を持つカウンターです。","ENG":"Senior Isolde is a Counter with an ability to multi-thinking.","TWN":"前輩是擁有一心多用能力的制裁者。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"가끔 통제를 잃고 굉장히 소심하거나 험악해지는 것만 아니면, 유용한 능력이죠.","JPN":"たまに統制を失って気が弱くなったり、険悪になったりすることを除けば、役に立つ能力です。","ENG":"It's a useful ability, despite the fact that she might lose control and become extremely timid or aggressive.","TWN":"只要不偶爾失控變得過於膽怯或者過於暴躁，這還是個非常有用的能力。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그거 혹시… 여러 사람의 인격이 들어있는 건가요?","JPN":"それ、もしかして……色んな人の人格が入ってるんですか？","ENG":"Then... does she have multiple personalities inside of her?","TWN":"意思是……她有好幾種人格嗎……？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잡담은 됐고, 용건이나 말해.","JPN":"無駄話はいいから、用件だけ話してよ。","ENG":"Let's cut the chit-chat and get to the point.","TWN":"閒聊到此為止，讓我們進入正題吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지금 어디야?","JPN":"今どこなの？","ENG":"Where are you right now?","TWN":"你們現在到哪了？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우린 지금 그라운드 제로의 목적지에 도착했네.","JPN":"私たちは今、グラウンド・ゼロの目的地に到着した。","ENG":"We've arrived at our destination, Ground Zero.","TWN":"我們已經到達目的地了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>우물</color>이라고 불리는, 아주 작은 크기의 차원 터널 앞에 있지.","JPN":"<color=#ffd34c>井戸</color>と呼ばれている、とても小さな次元トンネルの前にいる。","ENG":"We're right in front of a miniature dimension tunnel that they call the <color=#ffd34c>Well</color>.","TWN":"正站在稱為<color=#ffd34c>井</color>的極狹窄次元隧道前面。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐… 뭐? 이제 막 국경을 넘은 게 아니라 벌써 목적지에 도착했다고?!","JPN":"ちょっと……は？　国境を越えたんじゃなくて、もう目的地に着いたの！？","ENG":"Wait... What? You didn't just cross the border, but you're already there?!","TWN":"等一下……什麼？我以為剛剛越過國境呢，你們已經到達目的地了？!"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"균열을 둘러싼 밸브의 보안시스템을 내 도움도 없이 뚫었단 말이야?","JPN":"亀裂を囲んでいるバルブの保安システムを、私の助けなしで突破したってこと？","ENG":"You're telling me that you bypassed the Valve's security surrounding the Crevice without my help?","TWN":"竟然在沒有我説明的情況下破解了圍繞峽谷的閥門安全系統？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"말씀하신 밸브의 관문은 저희가 갔을 때 운석에 맞은 것처럼 망가져 있었습니다.","JPN":"そのバルブの関門は、私たちが着いた時には隕石が衝突したように破壊されていました。","ENG":"The Valve gate you mentioned was damaged as if it had been hit by a meteorite.","TWN":"你提到的閥門關口在我們到達時已經像被隕石擊中一樣損壞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그와는 별개로, 상부 지시를 받은 군인이 저희를 안내해주더군요.","JPN":"それとは別に、上層部から指示を受けた軍人が私たちを案内してくれたんです。","ENG":"Separately from that, soldiers with orders from their superiors escorted us here.","TWN":"除此之外，是接到了北方和議會上級指示的士兵帶我們來到了這裡。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"참모총장의 지시라는 이유만으로 신원확인 절차 없이 밸브를 통과했습니다.","JPN":"総参謀長の指示という理由だけで、身元を確認することなくバルブを通れたのです。","ENG":"So, we were able to pass the Valve without any identification procedures simply because it was an order from the Chief of the General Staff.","TWN":"因此，單憑參謀總長的指示，我們沒有經過身份驗證程序就通過了閥門。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐야 그게…? 무슨 함정 같은 건가?","JPN":"何それ……？　何かの罠？","ENG":"What the...? Could it be some kind of trap?","TWN":"那是什麼……？是陷阱嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"함정이라해도 목적지에 무사히 도착했단 사실은 변함없네.","JPN":"罠だとしても目的地に無事到着した事実に変わりはない。","ENG":"Even if it is, it doesn't change the fact that we arrived safely at our destination.","TWN":"即使是陷阱，總之是順利到達目的地了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"계획을 차질 없이 진행할 수 있다는 뜻이지.","JPN":"支障なく計画を進行できるという意味さ。","ENG":"This means that we can proceed with our plan without any issues.","TWN":"這就表示計畫進行順利。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…알겠어. 원격 모듈을 조정할 테니 2분 30초 기다려.","JPN":"……わかった。遠隔モジュールを調整するから、2分30秒待ってて。","ENG":"...All right. I'll adjust the remote module, so give me 2 minutes and 30 seconds.","TWN":"……知道了。我調整下遠端模組，我需要2分30秒。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"분석 결과. 그 <color=#ffd34c>우물</color>이라는 장소에서 다이브를 시도한 흔적을 발견했어.","JPN":"分析結果。あの<color=#ffd34c>井戸</color>って場所からダイブしようとして痕跡を発見した。","ENG":"From the result of my analysis, I found traces of dive attempts at this <color=#ffd34c>Well</color> place.","TWN":"分析結果顯示，在<color=#ffd34c>井</color>的周圍有嘗試躍入的痕跡。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이 흔적은 당신 말처럼 관리국에 등록된 죄수 패러독스의 고유 CRF파형과 일치해.","JPN":"この痕跡はあなたの言うとおり、管理局に登録された囚人パラドックスの固有CRFの波形と一致してる。","ENG":"These traces, as you said, match the unique CRF wavelengths of a prisoner named Paradox registered with the Administration.","TWN":"這個痕跡和你說的一樣，與管理局登記的罪犯悖論的專屬CRF波形一致。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무사히 다이브에 성공한 거라면, 갑자기 연락이 끊긴 이유도 설명이 되는군.","JPN":"無事ダイブに成功したのなら、急に連絡が途絶えた理由も説明がつくな。","ENG":"So if the dive was successful, it could explain why we couldn't suddenly reach her.","TWN":"嗯，如果是成功躍入的話，突然失聯的原因也就解釋得通了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"통보도 없이 사라져서 걱정했는데, 기우였던 모양이야.","JPN":"通報もなく消えて心配したんだが、杞憂だったようだ。","ENG":"I was worried because she disappeared without notice, but it seems my worries were for naught.","TWN":"她沒先說一聲就消失了，我還擔心了一下，看來是我多慮了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};